def get_alpha(query: str) -> float:
    if '"' in query:
        return 0.2   # Exact phrase — strong keyword preference
    elif any(c.isdigit() for c in query):
        return 0.3   # Product/ref codes — keyword preference
    elif len(query.split()) <= 3:
        return 0.5   # Short query — balanced
    else:
        return 0.7   # Natural language — semantic preference
